using Microsoft.EntityFrameworkCore;

// Cosmos DB EF Core 9 migration fixes for an existing container
// with documents that use the old "Discriminator" property format.
class CosmosDbContext : DbContext
{
    public DbSet<Session> Sessions => Set<Session>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Session>(entity =>
        {
            // Fix 1: EF Core 9 renamed the default discriminator from
            //         "Discriminator" to "$type". Existing documents still
            //         use "Discriminator", so pin it explicitly.
            entity.HasDiscriminator<string>("Discriminator");

            // Fix 2: EF Core 9 changed the id format from "EntityType|Key"
            //         to just "Key". Existing documents have the old compound
            //         format, so opt in to keep compatibility.
            entity.HasRootDiscriminatorInJsonId(true);
        });
    }

    // Fix 3: Cosmos DB provider no longer supports synchronous I/O.
    //         All sync calls (ToList, SaveChanges, etc.) must become async.
    //
    // BEFORE (throws InvalidOperationException in EF Core 9):
    //   var sessions = db.Sessions.ToList();
    //   db.SaveChanges();
    //
    // AFTER:
    //   var sessions = await db.Sessions.ToListAsync();
    //   await db.SaveChangesAsync();
}

class Session
{
    public string Id { get; set; } = null!;
    public string Title { get; set; } = null!;
}

